-- ==================================================================
-- CORREZIONE SALDI — versione robusta (aggancio via users.email)
-- Fix bug: gli UPDATE originali usavano company_id, NULL per i privati,
--          quindi i conti privati NON venivano aggiornati (es. David ×100).
-- Questo script aggancia i conti via owner_user_id -> users.email,
-- che esiste per privati E aziende. Infine ribilancia la Cassa Circuito.
-- ==================================================================
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
START TRANSACTION;

-- STEP 1: saldi/limiti corretti per tutti i membri (privati inclusi)
