-- STEP 2: ribilancia la Cassa Circuito = -(somma saldi membri)
UPDATE accounts a
JOIN (SELECT COALESCE(SUM(available_balance),0) s FROM accounts WHERE is_system_account=0) t
SET a.available_balance = -t.s, a.updated_at = NOW()
WHERE a.is_system_account = 1;

COMMIT;
